8681       cast<VPBasicBlock>(Plan.getVectorLoopRegion()->getSingleSuccessor());
8682   // No edge from the middle block to the unique exit block has been inserted
8683   // and there is nothing to fix from vector loop; phis should have incoming
8684   // from scalar loop only.
8685   if (MiddleVPBB->getNumSuccessors() != 2)
8686     return {};
8687   SetVector<VPIRInstruction *> ExitUsersToFix;
8688   VPBasicBlock *ExitVPBB = cast<VPIRBasicBlock>(MiddleVPBB->getSuccessors()[0]);
8689   BasicBlock *ExitingBB = OrigLoop->getExitingBlock();
8690   for (VPRecipeBase &R : *ExitVPBB) {
8691     auto *ExitIRI = dyn_cast<VPIRInstruction>(&R);
8692     if (!ExitIRI)
8693       continue;
8694     auto *ExitPhi = dyn_cast<PHINode>(&ExitIRI->getInstruction());
8695     if (!ExitPhi)
8696       break;
8697     Value *IncomingValue = ExitPhi->getIncomingValueForBlock(ExitingBB);
8698     VPValue *V = Builder.getVPValueOrAddLiveIn(IncomingValue);
8699     // Exit values for inductions are computed and updated outside of VPlan and
8700     // independent of induction recipes.
8701     // TODO: Compute induction exit values in VPlan, use VPLiveOuts to update
8702     // live-outs.
8703     if ((isa<VPWidenIntOrFpInductionRecipe>(V) &&
8704          !cast<VPWidenIntOrFpInductionRecipe>(V)->getTruncInst()) ||
8705         isa<VPWidenPointerInductionRecipe>(V) ||
8706         (isa<Instruction>(IncomingValue) &&
8707          OrigLoop->contains(cast<Instruction>(IncomingValue)) &&
8708          any_of(IncomingValue->users(), [&Inductions](User *U) {
8709            auto *P = dyn_cast<PHINode>(U);
8710            return P && Inductions.contains(P);
8711          })))
