8719 // Add exit values to \p Plan. Extracts are added for each entry in \p
8720 // ExitUsersToFix if needed and their operands are updated.
8721 static void
8722 addUsersInExitBlock(VPlan &Plan,
8723                     const SetVector<VPIRInstruction *> &ExitUsersToFix) {
8724   if (ExitUsersToFix.empty())
8725     return;
8726 
8727   auto *MiddleVPBB =
8728       cast<VPBasicBlock>(Plan.getVectorLoopRegion()->getSingleSuccessor());
8729   BasicBlock *ExitBB =
8730       cast<VPIRBasicBlock>(MiddleVPBB->getSuccessors()[0])->getIRBasicBlock();
8731   VPBuilder B(MiddleVPBB, MiddleVPBB->getFirstNonPhi());
8732 
8733   // Introduce extract for exiting values and update the VPIRInstructions
8734   // modeling the corresponding LCSSA phis.
8735   for (VPIRInstruction *ExitIRI : ExitUsersToFix) {
8736     VPValue *V = ExitIRI->getOperand(0);
8737     // Pass live-in values used by exit phis directly through to the live-out.
8738     if (V->isLiveIn())
8739       continue;
8740 
8741     VPValue *Ext = B.createNaryOp(
8742         VPInstruction::ExtractFromEnd,
8743         {V, Plan.getOrAddLiveIn(ConstantInt::get(
8744                 IntegerType::get(ExitBB->getContext(), 32), 1))});
8745     ExitIRI->setOperand(0, Ext);
8746   }
8747 }
